import sys

class Solution:
    def rotateString(self, s: str, k: int) -> str:
        n = len(s)
        if n == 0:
            return s
        k %= n
        if k == 0:
            return s
        # rotate right by k: take last k chars + first n-k chars
        return s[-k:] + s[:-k]

