#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string rotateString(string s, int k) {
        int n = s.size();
        if (n == 0) return s;
        k %= n;
        if (k == 0) return s;
        // rotate right by k: last k chars + first n-k chars
        string res = s.substr(n - k) + s.substr(0, n - k);
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    if (!(cin >> s)) return 0;
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    string ans = sol.rotateString(s, k);
    cout << ans << "\n";
    return 0;
}
